    97	    @Override
    98	    public byte[] evaluateResponse(byte[] response) throws SaslException, SaslAuthenticationException {
    99	        try {
   100	            switch (state) {
   101	                case RECEIVE_CLIENT_FIRST_MESSAGE:
   102	                    this.clientFirstMessage = new ClientFirstMessage(response);
   103	                    this.scramExtensions = clientFirstMessage.extensions();
   104	                    if (!SUPPORTED_EXTENSIONS.containsAll(scramExtensions.map().keySet())) {
   105	                        log.debug("Unsupported extensions will be ignored, supported {}, provided {}",
   106	                                SUPPORTED_EXTENSIONS, scramExtensions.map().keySet());
