   111	                        this.username = ScramFormatter.username(saslName);
   112	                        NameCallback nameCallback = new NameCallback("username", username);
   113	                        ScramCredentialCallback credentialCallback;
   114	                        if (scramExtensions.tokenAuthenticated()) {
   115	                            DelegationTokenCredentialCallback tokenCallback = new DelegationTokenCredentialCallback();
   116	                            credentialCallback = tokenCallback;
   117	                            callbackHandler.handle(new Callback[]{nameCallback, tokenCallback});
